// Normalize and Denoise Logs
// This code processes raw logs to extract meaningful error information

const items = $input.all();
const normalizedLogs = [];

// Define noise patterns to filter out
const noisePatterns = [
  /debug/i,
  /info/i,
  /trace/i,
  /verbose/i
];

// Process each log entry
for (const item of items) {
  const logData = item.json;

  // Skip if log level is noise
  const logLevel = logData.level || logData.severity || '';
  const isNoise = noisePatterns.some(pattern => pattern.test(logLevel));

  if (isNoise) {
    continue;
  }

  // Extract key fields
  const normalizedLog = {
    timestamp: logData.timestamp || logData.time || logData['@timestamp'] || new Date().toISOString(),
    level: (logLevel || 'unknown').toLowerCase(),
    message: logData.message || logData.msg || logData.text || '',
    sessionId: logData.sessionId || logData.session_id || logData.requestId || logData.request_id || logData.traceId || 'unknown',
    service: logData.service || logData.serviceName || logData.app || 'unknown',
    error: logData.error || logData.exception || logData.stack || null,
    metadata: {
      host: logData.host || logData.hostname,
      environment: logData.environment || logData.env,
      userId: logData.userId || logData.user_id,
      endpoint: logData.endpoint || logData.path || logData.url
    }
  };

  // Only include logs with error or warning level
  if (normalizedLog.level === 'error' || normalizedLog.level === 'warn' || normalizedLog.level === 'warning' || normalizedLog.level === 'fatal' || normalizedLog.level === 'critical') {
    normalizedLogs.push({
      json: normalizedLog
    });
  }
}

// Group logs by session/request ID
const groupedLogs = {};
for (const log of normalizedLogs) {
  const sessionId = log.json.sessionId;
  if (!groupedLogs[sessionId]) {
    groupedLogs[sessionId] = [];
  }
  groupedLogs[sessionId].push(log.json);
}

// Create output with grouped logs
const output = [];
for (const [sessionId, logs] of Object.entries(groupedLogs)) {
  // Sort logs by timestamp
  logs.sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp));

  output.push({
    json: {
      sessionId: sessionId,
      logCount: logs.length,
      firstError: logs[0].timestamp,
      lastError: logs[logs.length - 1].timestamp,
      service: logs[0].service,
      errors: logs.map(log => ({
        timestamp: log.timestamp,
        level: log.level,
        message: log.message,
        error: log.error,
        metadata: log.metadata
      }))
    }
  });
}

return output.length > 0 ? output : [{ json: { message: 'No error logs found after denoising' } }];

// Analyze vector store clusters to identify dominant failure patterns
const items = $input.all();

// Group items by cluster or similarity
const clusters = {};
const errorTypes = {};

for (const item of items) {
  const data = item.json;

  // Extract error information
  const errorType = data.error_type || data.level || data.severity || 'unknown';
  const message = data.message || data.log || data.text || '';
  const timestamp = data.timestamp || data.time || new Date().toISOString();

  // Count error types
  if (!errorTypes[errorType]) {
    errorTypes[errorType] = {
      count: 0,
      messages: [],
      timestamps: []
    };
  }
  errorTypes[errorType].count++;
  errorTypes[errorType].messages.push(message);
  errorTypes[errorType].timestamps.push(timestamp);

  // Group by cluster if available (from vector store)
  const clusterId = data.cluster_id || data.group || 'default';
  if (!clusters[clusterId]) {
    clusters[clusterId] = {
      id: clusterId,
      size: 0,
      errors: [],
      errorTypes: {}
    };
  }
  clusters[clusterId].size++;
  clusters[clusterId].errors.push(data);

  if (!clusters[clusterId].errorTypes[errorType]) {
    clusters[clusterId].errorTypes[errorType] = 0;
  }
  clusters[clusterId].errorTypes[errorType]++;
}

// Sort error types by frequency
const sortedErrorTypes = Object.entries(errorTypes)
  .map(([type, data]) => ({
    type,
    count: data.count,
    percentage: (data.count / items.length * 100).toFixed(2),
    sample_messages: data.messages.slice(0, 5),
    first_occurrence: data.timestamps.sort()[0],
    last_occurrence: data.timestamps.sort()[data.timestamps.length - 1]
  }))
  .sort((a, b) => b.count - a.count);

// Identify dominant patterns in each cluster
const clusterAnalysis = Object.values(clusters).map(cluster => {
  const dominantError = Object.entries(cluster.errorTypes)
    .sort((a, b) => b[1] - a[1])[0];

  return {
    cluster_id: cluster.id,
    size: cluster.size,
    dominant_error_type: dominantError ? dominantError[0] : 'unknown',
    dominant_error_count: dominantError ? dominantError[1] : 0,
    error_diversity: Object.keys(cluster.errorTypes).length,
    all_error_types: cluster.errorTypes
  };
}).sort((a, b) => b.size - a.size);

// Calculate overall statistics
const totalErrors = items.length;
const uniqueErrorTypes = Object.keys(errorTypes).length;
const largestCluster = clusterAnalysis[0] || { size: 0 };

// Return analysis results
return [{
  json: {
    summary: {
      total_errors: totalErrors,
      unique_error_types: uniqueErrorTypes,
      total_clusters: Object.keys(clusters).length,
      largest_cluster_size: largestCluster.size
    },
    top_error_types: sortedErrorTypes.slice(0, 10),
    cluster_analysis: clusterAnalysis,
    failure_patterns: {
      most_frequent_error: sortedErrorTypes[0]?.type || 'none',
      most_frequent_count: sortedErrorTypes[0]?.count || 0,
      error_concentration: sortedErrorTypes[0] ? 
        (sortedErrorTypes[0].count / totalErrors * 100).toFixed(2) + '%' : '0%'
    },
    raw_data: items.map(item => item.json)
  }
}];

// Time-align failure patterns with deployments, config changes, and traffic spikes
// Correlate timestamps and identify causal relationships

const items = $input.all();

// Extract and categorize events by type
const failurePatterns = [];
const deployments = [];
const configChanges = [];
const trafficSpikes = [];

items.forEach(item => {
  const data = item.json;

  if (data.type === 'failure_pattern') {
    failurePatterns.push(data);
  } else if (data.type === 'deployment') {
    deployments.push(data);
  } else if (data.type === 'config_change') {
    configChanges.push(data);
  } else if (data.type === 'traffic_spike') {
    trafficSpikes.push(data);
  }
});

// Function to parse timestamps
function parseTimestamp(ts) {
  return new Date(ts).getTime();
}

// Function to find temporal correlations (within time window)
function findCorrelations(failureEvent, events, windowMinutes = 30) {
  const failureTime = parseTimestamp(failureEvent.timestamp);
  const windowMs = windowMinutes * 60 * 1000;

  return events.filter(event => {
    const eventTime = parseTimestamp(event.timestamp);
    const timeDiff = failureTime - eventTime;
    // Event should occur before or around the same time as failure
    return timeDiff >= 0 && timeDiff <= windowMs;
  }).map(event => ({
    ...event,
    timeDiffMinutes: Math.round((failureTime - parseTimestamp(event.timestamp)) / 60000),
    correlationStrength: 1 - ((failureTime - parseTimestamp(event.timestamp)) / windowMs)
  }));
}

// Correlate each failure pattern with potential causes
const correlatedEvents = failurePatterns.map(failure => {
  const correlatedDeployments = findCorrelations(failure, deployments, 60);
  const correlatedConfigChanges = findCorrelations(failure, configChanges, 30);
  const correlatedTrafficSpikes = findCorrelations(failure, trafficSpikes, 15);

  // Calculate causal likelihood scores
  const causalRelationships = [];

  correlatedDeployments.forEach(dep => {
    causalRelationships.push({
      type: 'deployment',
      event: dep,
      causalScore: dep.correlationStrength * 0.9, // Deployments are highly likely causes
      reasoning: `Deployment occurred ${dep.timeDiffMinutes} minutes before failure`
    });
  });

  correlatedConfigChanges.forEach(config => {
    causalRelationships.push({
      type: 'config_change',
      event: config,
      causalScore: config.correlationStrength * 0.85,
      reasoning: `Config change occurred ${config.timeDiffMinutes} minutes before failure`
    });
  });

  correlatedTrafficSpikes.forEach(spike => {
    causalRelationships.push({
      type: 'traffic_spike',
      event: spike,
      causalScore: spike.correlationStrength * 0.7,
      reasoning: `Traffic spike occurred ${spike.timeDiffMinutes} minutes before failure`
    });
  });

  // Sort by causal score
  causalRelationships.sort((a, b) => b.causalScore - a.causalScore);

  return {
    json: {
      failurePattern: failure,
      correlatedEvents: {
        deployments: correlatedDeployments,
        configChanges: correlatedConfigChanges,
        trafficSpikes: correlatedTrafficSpikes
      },
      causalRelationships: causalRelationships,
      topLikelyCause: causalRelationships[0] || null,
      timestamp: failure.timestamp
    }
  };
});

return correlatedEvents;

